import { Router } from "express";
import { db, attemptsTable, attemptAnswersTable, resultsTable, examsTable, examQuestionsTable, questionsTable, usersTable } from "@workspace/db";
import { eq, and } from "drizzle-orm";
import { requireAuth } from "../middlewares/auth";
import type { Request, Response } from "express";
import type { AuthPayload } from "../middlewares/auth";

const router = Router();

function formatAttempt(a: typeof attemptsTable.$inferSelect, studentName?: string | null, examTitle?: string | null) {
  return {
    id: a.id,
    studentId: a.studentId,
    studentName: studentName ?? null,
    examId: a.examId,
    examTitle: examTitle ?? null,
    status: a.status,
    score: null,
    startedAt: a.startedAt.toISOString(),
    submittedAt: a.submittedAt?.toISOString() ?? null,
  };
}

router.get("/attempts", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const { studentId, examId } = req.query;
  const conditions = [];
  if (studentId) conditions.push(eq(attemptsTable.studentId, Number(studentId)));
  if (examId) conditions.push(eq(attemptsTable.examId, Number(examId)));
  const rows = await db.select().from(attemptsTable).where(conditions.length > 0 ? and(...conditions) : undefined).orderBy(attemptsTable.startedAt);
  const results = await Promise.all(rows.map(async (a) => {
    const [s] = await db.select({ name: usersTable.name }).from(usersTable).where(eq(usersTable.id, a.studentId)).limit(1);
    const [e] = await db.select({ title: examsTable.title }).from(examsTable).where(eq(examsTable.id, a.examId)).limit(1);
    const [result] = await db.select().from(resultsTable).where(eq(resultsTable.attemptId, a.id)).limit(1);
    return { ...formatAttempt(a, s?.name, e?.title), score: result?.score ?? null };
  }));
  res.json(results);
});

router.post("/attempts", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const authUser = (req as Request & { user: AuthPayload }).user;
  const { examId } = req.body;
  if (!examId) { res.status(400).json({ error: "examId required" }); return; }
  const [exam] = await db.select().from(examsTable).where(eq(examsTable.id, examId)).limit(1);
  if (!exam) { res.status(404).json({ error: "Exam not found" }); return; }

  const [attempt] = await db.insert(attemptsTable).values({
    studentId: authUser.userId, examId, status: "in_progress",
  }).returning();

  const eqs = await db.select().from(examQuestionsTable).where(eq(examQuestionsTable.examId, examId)).orderBy(examQuestionsTable.orderIndex);
  let questionsList = await Promise.all(eqs.map(async (eq2) => {
    const [q] = await db.select().from(questionsTable).where(eq(questionsTable.id, eq2.questionId)).limit(1);
    if (!q) return null;
    return {
      id: eq2.id,
      questionId: q.id,
      text: q.text,
      type: q.type,
      options: q.type === "mcq" || q.type === "matching" ? q.options : null,
      points: q.points,
      studentAnswer: null,
      codeLanguage: q.codeLanguage,
    };
  }));

  if (exam.shuffleQuestions) {
    questionsList = questionsList.sort(() => Math.random() - 0.5);
  }

  res.status(201).json({
    id: attempt.id,
    studentId: attempt.studentId,
    examId: attempt.examId,
    examTitle: exam.title,
    durationMinutes: exam.durationMinutes,
    status: attempt.status,
    startedAt: attempt.startedAt.toISOString(),
    submittedAt: null,
    questions: questionsList.filter(Boolean),
  });
});

router.get("/attempts/:id", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const id = Number(req.params.id);
  const [attempt] = await db.select().from(attemptsTable).where(eq(attemptsTable.id, id)).limit(1);
  if (!attempt) { res.status(404).json({ error: "Not found" }); return; }
  const [exam] = await db.select().from(examsTable).where(eq(examsTable.id, attempt.examId)).limit(1);
  const eqs = await db.select().from(examQuestionsTable).where(eq(examQuestionsTable.examId, attempt.examId)).orderBy(examQuestionsTable.orderIndex);
  const savedAnswers = await db.select().from(attemptAnswersTable).where(eq(attemptAnswersTable.attemptId, id));

  const questions = await Promise.all(eqs.map(async (eq2) => {
    const [q] = await db.select().from(questionsTable).where(eq(questionsTable.id, eq2.questionId)).limit(1);
    if (!q) return null;
    const savedAnswer = savedAnswers.find(a => a.questionId === q.id);
    return {
      id: eq2.id,
      questionId: q.id,
      text: q.text,
      type: q.type,
      options: q.type === "mcq" || q.type === "matching" ? q.options : null,
      points: q.points,
      studentAnswer: savedAnswer?.answer ?? null,
      codeLanguage: q.codeLanguage,
    };
  }));

  res.json({
    id: attempt.id,
    studentId: attempt.studentId,
    examId: attempt.examId,
    examTitle: exam?.title ?? null,
    durationMinutes: exam?.durationMinutes ?? 60,
    status: attempt.status,
    startedAt: attempt.startedAt.toISOString(),
    submittedAt: attempt.submittedAt?.toISOString() ?? null,
    questions: questions.filter(Boolean),
  });
});

router.post("/attempts/:id/answer", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const attemptId = Number(req.params.id);
  const { questionId, answer } = req.body;
  if (!questionId) { res.status(400).json({ error: "questionId required" }); return; }

  const existing = await db.select().from(attemptAnswersTable)
    .where(and(eq(attemptAnswersTable.attemptId, attemptId), eq(attemptAnswersTable.questionId, questionId)));

  if (existing.length > 0) {
    await db.update(attemptAnswersTable).set({ answer, savedAt: new Date() })
      .where(and(eq(attemptAnswersTable.attemptId, attemptId), eq(attemptAnswersTable.questionId, questionId)));
  } else {
    await db.insert(attemptAnswersTable).values({ attemptId, questionId, answer });
  }
  res.json({ success: true });
});

router.post("/attempts/:id/submit", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const attemptId = Number(req.params.id);
  const [attempt] = await db.select().from(attemptsTable).where(eq(attemptsTable.id, attemptId)).limit(1);
  if (!attempt) { res.status(404).json({ error: "Not found" }); return; }

  await db.update(attemptsTable).set({ status: "submitted", submittedAt: new Date() }).where(eq(attemptsTable.id, attemptId));

  const eqs = await db.select().from(examQuestionsTable).where(eq(examQuestionsTable.examId, attempt.examId));
  const savedAnswers = await db.select().from(attemptAnswersTable).where(eq(attemptAnswersTable.attemptId, attemptId));

  let score = 0;
  let totalPoints = 0;
  let hasPendingManual = false;

  for (const eq2 of eqs) {
    const [q] = await db.select().from(questionsTable).where(eq(questionsTable.id, eq2.questionId)).limit(1);
    if (!q) continue;
    totalPoints += q.points;
    const savedAnswer = savedAnswers.find(a => a.questionId === q.id);

    let pointsEarned = 0;
    let isCorrect: number | null = null;

    if (q.type === "essay" || q.type === "code") {
      hasPendingManual = true;
    } else if (savedAnswer?.answer && q.correctAnswer) {
      const correct = savedAnswer.answer.trim().toLowerCase() === q.correctAnswer.trim().toLowerCase();
      isCorrect = correct ? 1 : 0;
      pointsEarned = correct ? q.points : 0;
    }

    score += pointsEarned;

    await db.update(attemptAnswersTable).set({ pointsEarned, isCorrect })
      .where(and(eq(attemptAnswersTable.attemptId, attemptId), eq(attemptAnswersTable.questionId, q.id)));
  }

  const percentage = totalPoints > 0 ? (score / totalPoints) * 100 : 0;
  const [exam] = await db.select().from(examsTable).where(eq(examsTable.id, attempt.examId)).limit(1);
  const isPassed = percentage >= (exam?.passingScore ?? 50) ? 1 : 0;
  const gradingStatus = hasPendingManual ? "pending_manual" : "auto_graded";

  const [result] = await db.insert(resultsTable).values({
    attemptId, studentId: attempt.studentId, examId: attempt.examId,
    score, totalPoints, percentage, isPassed, gradingStatus,
  }).returning();

  res.json({
    id: result.id,
    attemptId: result.attemptId,
    studentId: result.studentId,
    studentName: null,
    examId: result.examId,
    examTitle: exam?.title ?? null,
    score: result.score,
    totalPoints: result.totalPoints,
    percentage: result.percentage,
    isPassed: result.isPassed === 1,
    gradingStatus: result.gradingStatus,
    createdAt: result.createdAt.toISOString(),
  });
});

export default router;

import { Router } from "express";
import { db, resultsTable, attemptsTable, attemptAnswersTable, questionsTable, usersTable, examsTable } from "@workspace/db";
import { eq, and } from "drizzle-orm";
import { requireAuth } from "../middlewares/auth";
import type { Request, Response } from "express";

const router = Router();

async function formatResult(r: typeof resultsTable.$inferSelect) {
  const [s] = await db.select({ name: usersTable.name }).from(usersTable).where(eq(usersTable.id, r.studentId)).limit(1);
  const [e] = await db.select({ title: examsTable.title }).from(examsTable).where(eq(examsTable.id, r.examId)).limit(1);
  return {
    id: r.id,
    attemptId: r.attemptId,
    studentId: r.studentId,
    studentName: s?.name ?? null,
    examId: r.examId,
    examTitle: e?.title ?? null,
    score: r.score,
    totalPoints: r.totalPoints,
    percentage: r.percentage,
    isPassed: r.isPassed === 1,
    gradingStatus: r.gradingStatus,
    createdAt: r.createdAt.toISOString(),
  };
}

router.get("/results", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const { studentId, examId } = req.query;
  const conditions = [];
  if (studentId) conditions.push(eq(resultsTable.studentId, Number(studentId)));
  if (examId) conditions.push(eq(resultsTable.examId, Number(examId)));
  const rows = await db.select().from(resultsTable).where(conditions.length > 0 ? and(...conditions) : undefined).orderBy(resultsTable.createdAt);
  const results = await Promise.all(rows.map(formatResult));
  res.json(results);
});

router.get("/results/:id", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const id = Number(req.params.id);
  const [r] = await db.select().from(resultsTable).where(eq(resultsTable.id, id)).limit(1);
  if (!r) { res.status(404).json({ error: "Not found" }); return; }

  const [exam] = await db.select().from(examsTable).where(eq(examsTable.id, r.examId)).limit(1);
  const answers = await db.select().from(attemptAnswersTable).where(eq(attemptAnswersTable.attemptId, r.attemptId));

  const answerDetails = await Promise.all(answers.map(async (a) => {
    const [q] = await db.select().from(questionsTable).where(eq(questionsTable.id, a.questionId)).limit(1);
    return {
      questionId: a.questionId,
      questionText: q?.text ?? "",
      questionType: q?.type ?? "",
      studentAnswer: a.answer,
      correctAnswer: exam?.showResults ? q?.correctAnswer ?? null : null,
      pointsEarned: a.pointsEarned ?? 0,
      maxPoints: q?.points ?? 0,
      isCorrect: a.isCorrect != null ? Boolean(a.isCorrect) : null,
      feedback: a.feedback,
    };
  }));

  const base = await formatResult(r);
  res.json({ ...base, answers: answerDetails });
});

router.patch("/results/:id/grade", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const id = Number(req.params.id);
  const { answers } = req.body as { answers: Array<{ questionId: number; pointsEarned: number; feedback?: string }> };
  const [r] = await db.select().from(resultsTable).where(eq(resultsTable.id, id)).limit(1);
  if (!r) { res.status(404).json({ error: "Not found" }); return; }

  for (const grade of answers) {
    await db.update(attemptAnswersTable).set({
      pointsEarned: grade.pointsEarned,
      isCorrect: grade.pointsEarned > 0 ? 1 : 0,
      feedback: grade.feedback ?? null,
    }).where(and(eq(attemptAnswersTable.attemptId, r.attemptId), eq(attemptAnswersTable.questionId, grade.questionId)));
  }

  const allAnswers = await db.select().from(attemptAnswersTable).where(eq(attemptAnswersTable.attemptId, r.attemptId));
  const newScore = allAnswers.reduce((sum, a) => sum + (a.pointsEarned ?? 0), 0);
  const percentage = r.totalPoints > 0 ? (newScore / r.totalPoints) * 100 : 0;
  const [exam] = await db.select().from(examsTable).where(eq(examsTable.id, r.examId)).limit(1);
  const isPassed = percentage >= (exam?.passingScore ?? 50) ? 1 : 0;

  const [updated] = await db.update(resultsTable).set({
    score: newScore, percentage, isPassed, gradingStatus: "fully_graded",
  }).where(eq(resultsTable.id, id)).returning();

  res.json(await formatResult(updated));
});

export default router;

import { Router } from "express";
import { db, usersTable, coursesTable, examsTable, attemptsTable, resultsTable, enrollmentsTable } from "@workspace/db";
import { eq, avg, count, max, min, and } from "drizzle-orm";
import { requireAuth } from "../middlewares/auth";
import type { Request, Response } from "express";

const router = Router();

router.get("/analytics/overview", requireAuth, async (_req: Request, res: Response): Promise<void> => {
  const [studentsCount] = await db.select({ count: count() }).from(usersTable).where(eq(usersTable.role, "student"));
  const [lecturersCount] = await db.select({ count: count() }).from(usersTable).where(eq(usersTable.role, "lecturer"));
  const [coursesCount] = await db.select({ count: count() }).from(coursesTable);
  const [examsCount] = await db.select({ count: count() }).from(examsTable);
  const [activeExamsCount] = await db.select({ count: count() }).from(examsTable).where(eq(examsTable.status, "active"));
  const [attemptsCount] = await db.select({ count: count() }).from(attemptsTable);
  const [avgResult] = await db.select({ avg: avg(resultsTable.percentage) }).from(resultsTable);

  const results = await db.select().from(resultsTable).orderBy(resultsTable.createdAt).limit(100);
  const passCount = results.filter(r => r.isPassed === 1).length;
  const passRate = results.length > 0 ? (passCount / results.length) * 100 : 0;

  const allExams = await db.select().from(examsTable);
  const examsByStatus = ["draft", "published", "active", "closed"].map(status => ({
    label: status,
    count: allExams.filter(e => e.status === status).length,
  }));

  const scoreRanges = [
    { label: "0-20%", min: 0, max: 20 },
    { label: "21-40%", min: 21, max: 40 },
    { label: "41-60%", min: 41, max: 60 },
    { label: "61-80%", min: 61, max: 80 },
    { label: "81-100%", min: 81, max: 100 },
  ];
  const scoreDistribution = scoreRanges.map(range => ({
    label: range.label,
    count: results.filter(r => r.percentage >= range.min && r.percentage <= range.max).length,
  }));

  const recentAttempts = await db.select().from(attemptsTable).orderBy(attemptsTable.startedAt).limit(5);
  const recentActivity = await Promise.all(recentAttempts.map(async (a) => {
    const [s] = await db.select({ name: usersTable.name }).from(usersTable).where(eq(usersTable.id, a.studentId)).limit(1);
    const [e] = await db.select({ title: examsTable.title }).from(examsTable).where(eq(examsTable.id, a.examId)).limit(1);
    return {
      type: "exam_attempt",
      description: `${s?.name ?? "Student"} started "${e?.title ?? "exam"}"`,
      createdAt: a.startedAt.toISOString(),
    };
  }));

  res.json({
    totalStudents: Number(studentsCount?.count ?? 0),
    totalLecturers: Number(lecturersCount?.count ?? 0),
    totalCourses: Number(coursesCount?.count ?? 0),
    totalExams: Number(examsCount?.count ?? 0),
    activeExams: Number(activeExamsCount?.count ?? 0),
    totalAttempts: Number(attemptsCount?.count ?? 0),
    averageScore: Number(avgResult?.avg ?? 0),
    passRate,
    recentActivity,
    examsByStatus,
    scoreDistribution,
  });
});

router.get("/analytics/exams/:examId", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const examId = Number(req.params.examId);
  const [exam] = await db.select().from(examsTable).where(eq(examsTable.id, examId)).limit(1);
  if (!exam) { res.status(404).json({ error: "Not found" }); return; }

  const examResults = await db.select().from(resultsTable).where(eq(resultsTable.examId, examId));
  const totalAttempts = examResults.length;
  const avgScore = totalAttempts > 0 ? examResults.reduce((s, r) => s + r.percentage, 0) / totalAttempts : 0;
  const passCount = examResults.filter(r => r.isPassed === 1).length;
  const passRate = totalAttempts > 0 ? (passCount / totalAttempts) * 100 : 0;
  const highest = totalAttempts > 0 ? Math.max(...examResults.map(r => r.score)) : 0;
  const lowest = totalAttempts > 0 ? Math.min(...examResults.map(r => r.score)) : 0;

  const scoreRanges = [
    { label: "0-20%", min: 0, max: 20 },
    { label: "21-40%", min: 21, max: 40 },
    { label: "41-60%", min: 41, max: 60 },
    { label: "61-80%", min: 61, max: 80 },
    { label: "81-100%", min: 81, max: 100 },
  ];
  const scoreDistribution = scoreRanges.map(range => ({
    label: range.label,
    count: examResults.filter(r => r.percentage >= range.min && r.percentage <= range.max).length,
  }));

  res.json({
    examId,
    examTitle: exam.title,
    totalAttempts,
    averageScore: avgScore,
    passRate,
    highestScore: highest,
    lowestScore: lowest,
    questionPerformance: [],
    scoreDistribution,
  });
});

router.get("/analytics/students/:studentId", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const studentId = Number(req.params.studentId);
  const [student] = await db.select({ name: usersTable.name }).from(usersTable).where(eq(usersTable.id, studentId)).limit(1);

  const studentResults = await db.select().from(resultsTable).where(eq(resultsTable.studentId, studentId)).orderBy(resultsTable.createdAt);
  const totalAttempts = studentResults.length;
  const avgScore = totalAttempts > 0 ? studentResults.reduce((s, r) => s + r.percentage, 0) / totalAttempts : 0;
  const passCount = studentResults.filter(r => r.isPassed === 1).length;
  const passRate = totalAttempts > 0 ? (passCount / totalAttempts) * 100 : 0;

  const enrollments = await db.select().from(enrollmentsTable).where(eq(enrollmentsTable.studentId, studentId));
  const coursePerformance = await Promise.all(enrollments.map(async (e) => {
    const [c] = await db.select({ name: coursesTable.name }).from(coursesTable).where(eq(coursesTable.id, e.courseId)).limit(1);
    const courseExams = await db.select().from(examsTable).where(eq(examsTable.courseId, e.courseId));
    const examIds = courseExams.map(ex => ex.id);
    const courseResults = studentResults.filter(r => examIds.includes(r.examId));
    const courseAvg = courseResults.length > 0 ? courseResults.reduce((s, r) => s + r.percentage, 0) / courseResults.length : 0;
    return {
      courseId: e.courseId,
      courseName: c?.name ?? "",
      averageScore: courseAvg,
      examCount: courseExams.length,
    };
  }));

  const recentResults = studentResults.slice(-5).reverse();
  const formattedRecent = await Promise.all(recentResults.map(async (r) => {
    const [ex] = await db.select({ title: examsTable.title }).from(examsTable).where(eq(examsTable.id, r.examId)).limit(1);
    return {
      id: r.id, attemptId: r.attemptId, studentId: r.studentId, studentName: student?.name ?? null,
      examId: r.examId, examTitle: ex?.title ?? null, score: r.score, totalPoints: r.totalPoints,
      percentage: r.percentage, isPassed: r.isPassed === 1, gradingStatus: r.gradingStatus,
      createdAt: r.createdAt.toISOString(),
    };
  }));

  res.json({
    studentId,
    studentName: student?.name ?? "",
    totalAttempts,
    averageScore: avgScore,
    passRate,
    recentResults: formattedRecent,
    coursePerformance,
  });
});

router.get("/analytics/lecturer/:lecturerId", requireAuth, async (req: Request, res: Response): Promise<void> => {
  const lecturerId = Number(req.params.lecturerId);
  const [lecturer] = await db.select({ name: usersTable.name }).from(usersTable).where(eq(usersTable.id, lecturerId)).limit(1);
  const courses = await db.select().from(coursesTable).where(eq(coursesTable.lecturerId, lecturerId));
  const courseIds = courses.map(c => c.id);

  let totalStudents = 0;
  const examSummaries = [];

  for (const c of courses) {
    const [enrollCount] = await db.select({ count: count() }).from(enrollmentsTable).where(eq(enrollmentsTable.courseId, c.id));
    totalStudents += Number(enrollCount?.count ?? 0);
  }

  const allExams = courseIds.length > 0
    ? await db.select().from(examsTable).where(eq(examsTable.courseId, courses[0]?.id ?? 0))
    : [];

  for (const exam of allExams) {
    const examResults = await db.select().from(resultsTable).where(eq(resultsTable.examId, exam.id));
    const avgScore = examResults.length > 0 ? examResults.reduce((s, r) => s + r.percentage, 0) / examResults.length : 0;
    const passCount = examResults.filter(r => r.isPassed === 1).length;
    examSummaries.push({
      examId: exam.id,
      examTitle: exam.title,
      attemptCount: examResults.length,
      averageScore: avgScore,
      passRate: examResults.length > 0 ? (passCount / examResults.length) * 100 : 0,
    });
  }

  const allExamResults = await db.select().from(resultsTable);
  const courseExamIds = new Set(allExams.map(e => e.id));
  const relevantResults = allExamResults.filter(r => courseExamIds.has(r.examId));
  const avgClassScore = relevantResults.length > 0 ? relevantResults.reduce((s, r) => s + r.percentage, 0) / relevantResults.length : 0;

  res.json({
    lecturerId,
    lecturerName: lecturer?.name ?? "",
    totalCourses: courses.length,
    totalExams: allExams.length,
    totalStudents,
    averageClassScore: avgClassScore,
    examSummaries,
  });
});

export default router;

