   236→async function parseJsonBody(
   237→  response: Response,
   238→  requestInfo: { method: string; url: string },
   239→): Promise<unknown> {
   240→  const raw = await response.text();
   241→  const normalized = stripBom(raw);
   242→
   243→  if (normalized.trim() === "") {
   244→    return null;
   245→  }
   246→
   247→  try {
   248→    return JSON.parse(normalized);
   249→  } catch (cause) {
   250→    throw new ResponseParseError(response, raw, cause, requestInfo);
   251→  }
   252→}
   253→
   254→async function parseErrorBody(response: Response, method: string): Promise<unknown> {
   255→  if (hasNoBody(response, method)) {
   256→    return null;
   257→  }
   258→
   259→  const mediaType = getMediaType(response.headers);
   260→
   261→  // Fall back to text when blob() is unavailable (e.g. some React Native builds).
   262→  if (mediaType && !isJsonMediaType(mediaType) && !isTextMediaType(mediaType)) {
   263→    return typeof response.blob === "function" ? response.blob() : response.text();
   264→  }
   265→
   266→  const raw = await response.text();
   267→  const normalized = stripBom(raw);
   268→  const trimmed = normalized.trim();
   269→
   270→  if (trimmed === "") {
   271→    return null;
   272→  }
   273→
   274→  if (isJsonMediaType(mediaType) || looksLikeJson(normalized)) {
   275→    try {
   276→      return JSON.parse(normalized);
   277→    } catch {
   278→      return raw;
   279→    }
   280→  }
   281→
   282→  return raw;
   283→}
   284→
   285→function inferResponseType(response: Response): "json" | "text" | "blob" {
   286→  const mediaType = getMediaType(response.headers);
   287→
   288→  if (isJsonMediaType(mediaType)) return "json";
   289→  if (isTextMediaType(mediaType) || mediaType == null) return "text";
   290→  return "blob";
   291→}
   292→
   293→async function parseSuccessBody(
   294→  response: Response,
   295→  responseType: "json" | "text" | "blob" | "auto",
   296→  requestInfo: { method: string; url: string },
   297→): Promise<unknown> {
   298→  if (hasNoBody(response, requestInfo.method)) {
   299→    return null;
   300→  }
   301→
   302→  const effectiveType =
   303→    responseType === "auto" ? inferResponseType(response) : responseType;
   304→
   305→  switch (effectiveType) {
   306→    case "json":
   307→      return parseJsonBody(response, requestInfo);
   308→
   309→    case "text": {
   310→      const text = await response.text();
   311→      return text === "" ? null : text;
   312→    }
   313→
   314→    case "blob":
   315→      if (typeof response.blob !== "function") {
   316→        throw new TypeError(
   317→          "Blob responses are not supported in this runtime. " +
   318→            "Use responseType \"json\" or \"text\" instead.",
   319→        );
   320→      }
   321→      return response.blob();
   322→  }
   323→}
