   325→export async function customFetch<T = unknown>(
   326→  input: RequestInfo | URL,
   327→  options: CustomFetchOptions = {},
   328→): Promise<T> {
   329→  input = applyBaseUrl(input);
   330→  const { responseType = "auto", headers: headersInit, ...init } = options;
   331→
   332→  const method = resolveMethod(input, init.method);
   333→
   334→  if (init.body != null && (method === "GET" || method === "HEAD")) {
   335→    throw new TypeError(`customFetch: ${method} requests cannot have a body.`);
   336→  }
   337→
   338→  const headers = mergeHeaders(isRequest(input) ? input.headers : undefined, headersInit);
   339→
   340→  if (
   341→    typeof init.body === "string" &&
   342→    !headers.has("content-type") &&
   343→    looksLikeJson(init.body)
   344→  ) {
   345→    headers.set("content-type", "application/json");
   346→  }
   347→
   348→  if (responseType === "json" && !headers.has("accept")) {
   349→    headers.set("accept", DEFAULT_JSON_ACCEPT);
   350→  }
   351→
   352→  // Attach bearer token when an auth getter is configured and no
   353→  // Authorization header has been explicitly provided.
   354→  if (_authTokenGetter && !headers.has("authorization")) {
   355→    const token = await _authTokenGetter();
   356→    if (token) {
   357→      headers.set("authorization", `Bearer ${token}`);
   358→    }
   359→  }
   360→
   361→  const requestInfo = { method, url: resolveUrl(input) };
   362→
   363→  const response = await fetch(input, { ...init, method, headers });
   364→
   365→  if (!response.ok) {
   366→    const errorData = await parseErrorBody(response, method);
   367→    throw new ApiError(response, errorData, requestInfo);
   368→  }
   369→
   370→  return (await parseSuccessBody(response, responseType, requestInfo)) as T;
   371→}
