};

const typeBadge: Record<string, string> = {
  video: "bg-purple-100 text-purple-700",
  pdf: "bg-red-100 text-red-700",
  link: "bg-blue-100 text-blue-700",
  slide: "bg-orange-100 text-orange-700",
