                  </div>
                  <div className="flex gap-2 flex-wrap">
                    <Button size="sm" variant="outline" onClick={() => setViewing(a)}>View Submissions</Button>
                    {a.status === "draft" && <Button size="sm" variant="outline" onClick={() => updateStatus(a.id, "active")}>Publish</Button>}
                    {a.status === "active" && <Button size="sm" variant="outline" onClick={() => updateStatus(a.id, "closed")}>Close</Button>}
                    <Button size="sm" variant="ghost" className="text-destructive" onClick={() => deleteAssignment(a.id)}><Trash2 className="h-3.5 w-3.5" /></Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      {showForm && <AssignmentForm courses={courses} onClose={() => setShowForm(false)} onSave={() => qc.invalidateQueries({ queryKey: ["assignments"] })} />}
      {gradingSubmission && (
        <GradeModal
          submission={gradingSubmission.sub}
          totalPoints={gradingSubmission.totalPoints}
          onClose={() => setGradingSubmission(null)}
          onSave={() => qc.invalidateQueries({ queryKey: ["submissions", viewing?.id] })}
        />
      )}
    </DashboardLayout>
  );
}

import { useQuery } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { api } from "@/lib/api";
import { AlertTriangle, CheckCircle, Shield } from "lucide-react";
import { useState } from "react";

const VIOLATION_LABELS: Record<string, string> = {
  tab_switch: "Tab Switch",
  fullscreen_exit: "Fullscreen Exit",
  copy_paste: "Copy/Paste",
  focus_lost: "Focus Lost",
  right_click: "Right Click",
  keyboard_shortcut: "Keyboard Shortcut",
};

const VIOLATION_COLOR: Record<string, string> = {
  tab_switch: "bg-red-100 text-red-700",
  fullscreen_exit: "bg-orange-100 text-orange-700",
  copy_paste: "bg-red-100 text-red-700",
  focus_lost: "bg-yellow-100 text-yellow-700",
  right_click: "bg-orange-100 text-orange-700",
  keyboard_shortcut: "bg-purple-100 text-purple-700",
};

export default function LecturerProctoringPage() {
  const [selectedExam, setSelectedExam] = useState<any | null>(null);

  const { data: exams = [], isLoading } = useQuery<any[]>({ queryKey: ["exams"], queryFn: () => api.get("/exams") });
  const { data: report = [], isLoading: reportLoading } = useQuery<any[]>({
    queryKey: ["proctoring-report", selectedExam?.id],
    queryFn: () => api.get(`/exams/${selectedExam.id}/proctoring-report`),
    enabled: !!selectedExam,
  });

  const totalViolations = report.reduce((sum: number, r: any) => sum + r.violationCount, 0);
  const flagged = report.filter((r: any) => r.violationCount >= 3);

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold tracking-tight flex items-center gap-2">
            <Shield className="h-7 w-7" /> Proctoring Reports
          </h1>
          <p className="text-muted-foreground mt-1">Review academic integrity violations for your exams.</p>
        </div>

        <div>
          <label className="text-sm font-medium mb-2 block">Select Exam</label>
          <select
            className="border rounded-md px-3 py-2 text-sm bg-background w-full max-w-sm"
            value={selectedExam?.id ?? ""}
            onChange={(e) => setSelectedExam(exams.find((ex: any) => ex.id === Number(e.target.value)) ?? null)}
          >
            <option value="">Choose an exam...</option>
            {exams.map((ex: any) => <option key={ex.id} value={ex.id}>{ex.title}</option>)}
          </select>
        </div>

        {selectedExam && (
          reportLoading ? (
            <div className="space-y-3">
              {[1, 2, 3].map((i) => <Card key={i} className="h-24 animate-pulse bg-muted" />)}
            </div>
          ) : (
            <div className="space-y-6">
              <div className="grid gap-4 md:grid-cols-3">
                <Card>
                  <CardContent className="pt-6">
                    <div className="text-2xl font-bold">{report.length}</div>
                    <p className="text-sm text-muted-foreground">Total Attempts</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardContent className="pt-6">
                    <div className="text-2xl font-bold text-red-600">{totalViolations}</div>
                    <p className="text-sm text-muted-foreground">Total Violations</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardContent className="pt-6">
                    <div className="text-2xl font-bold text-orange-600">{flagged.length}</div>
                    <p className="text-sm text-muted-foreground">Flagged ({">"}=3 violations)</p>
                  </CardContent>
                </Card>
              </div>

              {report.length === 0 ? (
                <Card>
                  <CardContent className="py-12 flex flex-col items-center gap-2 text-muted-foreground">
                    <CheckCircle className="h-8 w-8 opacity-40 text-green-500" />
                    <p className="text-sm">No attempts yet for this exam.</p>
                  </CardContent>
                </Card>
              ) : (
                <div className="space-y-4">
                  {report.map((r: any) => (
                    <Card key={r.attempt.id} className={r.violationCount >= 3 ? "border-red-400" : ""}>
                      <CardHeader className="pb-3">
                        <div className="flex items-center justify-between">
                          <div>
                            <CardTitle className="text-base">Attempt #{r.attempt.id}</CardTitle>
                            <p className="text-xs text-muted-foreground">
                              Student ID: {r.attempt.studentId} · Started: {new Date(r.attempt.startedAt).toLocaleString()}
                              {r.attempt.submittedAt ? ` · Submitted: ${new Date(r.attempt.submittedAt).toLocaleString()}` : " · In Progress"}
                            </p>
                          </div>
                          {r.violationCount === 0 ? (
                            <Badge variant="outline" className="border-green-500 text-green-700 flex items-center gap-1">
                              <CheckCircle className="h-3 w-3" /> Clean
                            </Badge>
                          ) : (
                            <Badge variant="destructive" className="flex items-center gap-1">
                              <AlertTriangle className="h-3 w-3" /> {r.violationCount} violation{r.violationCount !== 1 ? "s" : ""}
                            </Badge>
                          )}
                        </div>
                      </CardHeader>
                      {r.violations.length > 0 && (
                        <CardContent>
                          <div className="space-y-2">
                            {r.violations.map((v: any) => (
                              <div key={v.id} className="flex items-center gap-3 text-xs">
                                <span className={`px-2 py-0.5 rounded-full font-medium ${VIOLATION_COLOR[v.type] ?? "bg-muted text-muted-foreground"}`}>
                                  {VIOLATION_LABELS[v.type] ?? v.type}
                                </span>
                                <span className="text-muted-foreground">{new Date(v.occurredAt).toLocaleTimeString()}</span>
                                {v.description && <span className="text-muted-foreground">· {v.description}</span>}
                              </div>
                            ))}
                          </div>
                        </CardContent>
                      )}
                    </Card>
                  ))}
                </div>
              )}
            </div>
          )
        )}
      </div>
    </DashboardLayout>
  );
}

import { useQuery, useQueryClient } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { FileText, Plus, Trash2 } from "lucide-react";
import { useState } from "react";

const QUESTION_TYPES = ["mcq", "true_false", "fill_blank", "essay", "matching", "code"];

function ExamForm({ courses, onClose, onSave }: { courses: any[]; onClose: () => void; onSave: () => void }) {
  const [form, setForm] = useState({ courseId: "", title: "", description: "", durationMinutes: "60", passingScore: "50", status: "draft" });
  const [saving, setSaving] = useState(false);
  const set = (k: string, v: string) => setForm((f) => ({ ...f, [k]: v }));

  const handleSave = async () => {
    if (!form.courseId || !form.title) { alert("Fill required fields"); return; }
    setSaving(true);
    try {
      await api.post("/exams", { ...form, courseId: Number(form.courseId), durationMinutes: Number(form.durationMinutes), passingScore: Number(form.passingScore) });
      onSave(); onClose();
    } catch (e: any) { alert(e.message); }
    setSaving(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-card rounded-lg border p-6 w-full max-w-md space-y-4">
        <h2 className="text-lg font-bold">Create Exam</h2>
        <div className="space-y-3">
          <div>
            <label className="text-sm font-medium mb-1 block">Course *</label>
            <select className="w-full border rounded-md px-3 py-2 text-sm bg-background" value={form.courseId} onChange={(e) => set("courseId", e.target.value)}>
              <option value="">Select course...</option>
              {courses.map((c: any) => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="text-sm font-medium mb-1 block">Title *</label>
            <Input value={form.title} onChange={(e) => set("title", e.target.value)} placeholder="Exam title..." />
          </div>
          <div>
            <label className="text-sm font-medium mb-1 block">Description</label>
            <textarea className="w-full border rounded-md px-3 py-2 text-sm min-h-[70px]" value={form.description} onChange={(e) => set("description", e.target.value)} placeholder="Instructions..." />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-sm font-medium mb-1 block">Duration (min)</label>
              <Input type="number" value={form.durationMinutes} onChange={(e) => set("durationMinutes", e.target.value)} />
            </div>
            <div>
              <label className="text-sm font-medium mb-1 block">Passing Score (%)</label>
              <Input type="number" value={form.passingScore} onChange={(e) => set("passingScore", e.target.value)} />
            </div>
          </div>
          <div>
            <label className="text-sm font-medium mb-1 block">Status</label>
            <select className="w-full border rounded-md px-3 py-2 text-sm bg-background" value={form.status} onChange={(e) => set("status", e.target.value)}>
              <option value="draft">Draft</option>
              <option value="active">Active</option>
            </select>
          </div>
        </div>
        <div className="flex gap-3 justify-end">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button onClick={handleSave} disabled={saving}>{saving ? "Saving..." : "Create"}</Button>
        </div>
      </div>
    </div>
  );
}

function QuestionForm({ examId, onClose, onSave }: { examId: number; onClose: () => void; onSave: () => void }) {
  const [form, setForm] = useState({ text: "", type: "mcq", points: "5", options: ["", "", "", ""], correctAnswer: "", difficulty: "medium" });
  const [saving, setSaving] = useState(false);
  const set = (k: string, v: any) => setForm((f) => ({ ...f, [k]: v }));

  const handleSave = async () => {
    if (!form.text) { alert("Question text required"); return; }
    setSaving(true);
    try {
      const opts = form.type === "mcq" ? form.options.filter(Boolean) : undefined;
      const q = await api.post<{ id: number }>("/questions", {
        text: form.text, type: form.type, points: Number(form.points),
        options: opts, correctAnswer: form.correctAnswer || null, difficulty: form.difficulty,
        courseId: null,
      });
      await api.post(`/exams/${examId}/questions`, { questionId: q.id });
      onSave(); onClose();
    } catch (e: any) { alert(e.message); }
    setSaving(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-card rounded-lg border p-6 w-full max-w-lg space-y-4 max-h-[90vh] overflow-y-auto">
        <h2 className="text-lg font-bold">Add Question</h2>
        <div className="space-y-3">
          <div>
            <label className="text-sm font-medium mb-1 block">Type</label>
            <select className="w-full border rounded-md px-3 py-2 text-sm bg-background" value={form.type} onChange={(e) => set("type", e.target.value)}>
              {QUESTION_TYPES.map((t) => <option key={t} value={t}>{t.replace("_", " ").toUpperCase()}</option>)}
            </select>
          </div>
          <div>
            <label className="text-sm font-medium mb-1 block">Question *</label>
            <textarea className="w-full border rounded-md px-3 py-2 text-sm min-h-[80px]" value={form.text} onChange={(e) => set("text", e.target.value)} placeholder="Enter question..." />
          </div>
          {form.type === "mcq" && (
            <div>
              <label className="text-sm font-medium mb-1 block">Options</label>
              {form.options.map((opt, i) => (
                <Input key={i} className="mb-2" value={opt} onChange={(e) => { const o = [...form.options]; o[i] = e.target.value; set("options", o); }} placeholder={`Option ${i + 1}`} />
              ))}
            </div>
          )}
          {(form.type === "mcq" || form.type === "true_false" || form.type === "fill_blank") && (
            <div>
              <label className="text-sm font-medium mb-1 block">Correct Answer</label>
              {form.type === "true_false" ? (
                <select className="w-full border rounded-md px-3 py-2 text-sm bg-background" value={form.correctAnswer} onChange={(e) => set("correctAnswer", e.target.value)}>
                  <option value="">Select...</option>
                  <option value="True">True</option>
                  <option value="False">False</option>
                </select>
              ) : (
                <Input value={form.correctAnswer} onChange={(e) => set("correctAnswer", e.target.value)} placeholder="Correct answer..." />
              )}
            </div>
          )}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-sm font-medium mb-1 block">Points</label>
              <Input type="number" value={form.points} onChange={(e) => set("points", e.target.value)} />
            </div>
            <div>
              <label className="text-sm font-medium mb-1 block">Difficulty</label>
              <select className="w-full border rounded-md px-3 py-2 text-sm bg-background" value={form.difficulty} onChange={(e) => set("difficulty", e.target.value)}>
                <option value="easy">Easy</option>
                <option value="medium">Medium</option>
                <option value="hard">Hard</option>
              </select>
            </div>
          </div>
        </div>
        <div className="flex gap-3 justify-end">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button onClick={handleSave} disabled={saving}>{saving ? "Saving..." : "Add Question"}</Button>
        </div>
      </div>
    </div>
  );
}

export default function LecturerExamsPage() {
  const [showExamForm, setShowExamForm] = useState(false);
  const [showQForm, setShowQForm] = useState<number | null>(null);
  const [viewing, setViewing] = useState<any | null>(null);
  const qc = useQueryClient();

  const { data: exams = [], isLoading } = useQuery<any[]>({ queryKey: ["exams"], queryFn: () => api.get("/exams") });
  const { data: courses = [] } = useQuery<any[]>({ queryKey: ["courses"], queryFn: () => api.get("/courses") });
  const { data: examQuestions = [] } = useQuery<any[]>({
    queryKey: ["exam-questions", viewing?.id],
    queryFn: () => api.get(`/exams/${viewing.id}/questions`),
    enabled: !!viewing,
  });

  const deleteExam = async (id: number) => {
    if (!confirm("Delete this exam?")) return;
    await api.del(`/exams/${id}`);
    qc.invalidateQueries({ queryKey: ["exams"] });
  };

  const publishExam = async (id: number, status: string) => {
    await api.put(`/exams/${id}`, { status });
    qc.invalidateQueries({ queryKey: ["exams"] });
  };

  const statusColor: Record<string, "default" | "secondary" | "outline"> = { active: "default", draft: "secondary", ended: "outline" };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">Exams & Questions</h1>
            <p className="text-muted-foreground mt-1">Create exams and build your question bank.</p>
          </div>
          <Button onClick={() => setShowExamForm(true)}><Plus className="h-4 w-4 mr-2" /> Create Exam</Button>
        </div>

        {viewing ? (
          <div className="space-y-4">
            <div className="flex items-center gap-3">
              <Button variant="outline" size="sm" onClick={() => setViewing(null)}>← Back</Button>
              <h2 className="text-xl font-semibold">{viewing.title} — Questions ({examQuestions.length})</h2>
              <Button size="sm" onClick={() => setShowQForm(viewing.id)}><Plus className="h-3.5 w-3.5 mr-1" /> Add Question</Button>
            </div>
            {examQuestions.length === 0 ? (
              <Card><CardContent className="py-8 text-center text-sm text-muted-foreground">No questions yet. Add some questions to this exam.</CardContent></Card>
            ) : (
              <div className="space-y-3">
                {examQuestions.map((q: any, i: number) => (
                  <Card key={q.id}>
                    <CardContent className="pt-4 pb-4">
                      <div className="flex items-start gap-3">
                        <span className="text-muted-foreground text-sm font-mono w-6 shrink-0">{i + 1}.</span>
                        <div className="flex-1">
                          <p className="text-sm">{q.text}</p>
                          {q.options && <p className="text-xs text-muted-foreground mt-1">Options: {q.options.join(", ")}</p>}
                          {q.correctAnswer && <p className="text-xs text-green-700 mt-0.5">Answer: {q.correctAnswer}</p>}
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                          <Badge variant="outline">{q.type.replace("_", " ")}</Badge>
                          <span className="text-xs text-muted-foreground">{q.points}pt</span>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </div>
        ) : isLoading ? (
          <div className="grid gap-4 md:grid-cols-2">
            {[1, 2].map((i) => <Card key={i} className="h-40 animate-pulse bg-muted" />)}
          </div>
        ) : exams.length === 0 ? (
          <Card>
            <CardContent className="py-12 flex flex-col items-center gap-2 text-muted-foreground">
              <FileText className="h-8 w-8 opacity-40" />
              <p className="text-sm">No exams yet. Create your first exam.</p>
            </CardContent>
          </Card>
        ) : (
          <div className="grid gap-4 md:grid-cols-2">
            {exams.map((exam: any) => (
              <Card key={exam.id} className="flex flex-col">
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between gap-2">
                    <CardTitle className="text-base">{exam.title}</CardTitle>
                    <Badge variant={statusColor[exam.status] ?? "secondary"}>{exam.status}</Badge>
                  </div>
                  <p className="text-sm text-muted-foreground">{exam.courseName}</p>
                </CardHeader>
                <CardContent className="flex-1 flex flex-col gap-3">
                  <div className="grid grid-cols-3 gap-2 text-xs text-muted-foreground">
                    <div><span className="font-medium text-foreground">{exam.durationMinutes}</span> min</div>
                    <div><span className="font-medium text-foreground">{exam.questionCount}</span> Qs</div>
                    <div><span className="font-medium text-foreground">{exam.attemptCount}</span> attempts</div>
                  </div>
                  <div className="flex gap-2 flex-wrap mt-auto">
                    <Button size="sm" variant="outline" onClick={() => setViewing(exam)}>View Questions</Button>
                    {exam.status === "draft" && <Button size="sm" variant="outline" onClick={() => publishExam(exam.id, "active")}>Publish</Button>}
                    {exam.status === "active" && <Button size="sm" variant="outline" onClick={() => publishExam(exam.id, "ended")}>End</Button>}
                    <Button size="sm" variant="ghost" className="text-destructive" onClick={() => deleteExam(exam.id)}><Trash2 className="h-3.5 w-3.5" /></Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      {showExamForm && <ExamForm courses={courses} onClose={() => setShowExamForm(false)} onSave={() => qc.invalidateQueries({ queryKey: ["exams"] })} />}
      {showQForm !== null && (
        <QuestionForm
          examId={showQForm}
          onClose={() => setShowQForm(null)}
          onSave={() => { qc.invalidateQueries({ queryKey: ["exam-questions", showQForm] }); }}
        />
      )}
    </DashboardLayout>
  );
}

import { useQuery, useQueryClient } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { Users } from "lucide-react";
import { useState } from "react";

const ROLE_COLORS: Record<string, string> = {
  super_admin: "bg-purple-100 text-purple-700",
  admin: "bg-blue-100 text-blue-700",
  lecturer: "bg-green-100 text-green-700",
  student: "bg-gray-100 text-gray-700",
};

export default function AdminUsersPage() {
  const [search, setSearch] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const qc = useQueryClient();

  const { data: users = [], isLoading } = useQuery<any[]>({
    queryKey: ["users"],
    queryFn: () => api.get("/users"),
  });

  const filtered = users.filter((u: any) => {
    const matchSearch = u.name.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase());
    const matchRole = roleFilter === "all" || u.role === roleFilter;
    return matchSearch && matchRole;
  });

  const toggleActive = async (user: any) => {
    await api.put(`/users/${user.id}`, { isActive: !user.isActive });
    qc.invalidateQueries({ queryKey: ["users"] });
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">User Management</h1>
          <p className="text-muted-foreground mt-1">Manage all platform users.</p>
        </div>

        <div className="flex gap-3 flex-wrap">
          <Input placeholder="Search name or email..." className="max-w-xs" value={search} onChange={(e) => setSearch(e.target.value)} />
          <select
            className="border rounded-md px-3 py-2 text-sm bg-background"
            value={roleFilter}
            onChange={(e) => setRoleFilter(e.target.value)}
          >
            <option value="all">All Roles</option>
            <option value="super_admin">Super Admin</option>
            <option value="admin">Admin</option>
            <option value="lecturer">Lecturer</option>
            <option value="student">Student</option>
          </select>
        </div>

        <div className="text-sm text-muted-foreground">{filtered.length} user{filtered.length !== 1 ? "s" : ""}</div>

        {isLoading ? (
          <div className="space-y-3">
            {[1, 2, 3].map((i) => <Card key={i} className="h-20 animate-pulse bg-muted" />)}
          </div>
        ) : filtered.length === 0 ? (
          <Card>
            <CardContent className="py-12 flex flex-col items-center gap-2 text-muted-foreground">
              <Users className="h-8 w-8 opacity-40" />
              <p className="text-sm">No users found.</p>
            </CardContent>
          </Card>
        ) : (
          <div className="border rounded-lg overflow-hidden">
            <table className="w-full text-sm">
              <thead className="bg-muted/40 border-b">
                <tr>
                  <th className="text-left px-4 py-3 font-medium text-muted-foreground">Name</th>
                  <th className="text-left px-4 py-3 font-medium text-muted-foreground">Email</th>
                  <th className="text-left px-4 py-3 font-medium text-muted-foreground">Role</th>
                  <th className="text-left px-4 py-3 font-medium text-muted-foreground">Department</th>
                  <th className="text-left px-4 py-3 font-medium text-muted-foreground">Status</th>
                  <th className="text-left px-4 py-3 font-medium text-muted-foreground">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((u: any, i: number) => (
                  <tr key={u.id} className={`border-b last:border-0 ${i % 2 === 0 ? "" : "bg-muted/20"}`}>
                    <td className="px-4 py-3 font-medium">{u.name}</td>
                    <td className="px-4 py-3 text-muted-foreground">{u.email}</td>
                    <td className="px-4 py-3">
                      <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${ROLE_COLORS[u.role] ?? "bg-muted"}`}>
                        {u.role.replace(/_/g, " ")}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-muted-foreground">{u.departmentName ?? "—"}</td>
                    <td className="px-4 py-3">
                      <Badge variant={u.isActive ? "default" : "secondary"}>{u.isActive ? "Active" : "Inactive"}</Badge>
                    </td>
                    <td className="px-4 py-3">
                      <Button size="sm" variant="outline" onClick={() => toggleActive(u)}>
                        {u.isActive ? "Deactivate" : "Activate"}
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </DashboardLayout>
  );
}

import { useQuery, useQueryClient } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { BookOpen, Plus } from "lucide-react";
import { useState } from "react";

function CourseForm({ departments, onClose, onSave }: { departments: any[]; onClose: () => void; onSave: () => void }) {
  const [form, setForm] = useState({ name: "", code: "", description: "", departmentId: "", credits: "3" });
  const [saving, setSaving] = useState(false);
  const set = (k: string, v: string) => setForm((f) => ({ ...f, [k]: v }));

  const handleSave = async () => {
    if (!form.name || !form.code) { alert("Name and code are required"); return; }
    setSaving(true);
    try {
      await api.post("/courses", { ...form, departmentId: form.departmentId ? Number(form.departmentId) : null, credits: Number(form.credits) });
      onSave(); onClose();
    } catch (e: any) { alert(e.message); }
    setSaving(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-card rounded-lg border p-6 w-full max-w-md space-y-4">
        <h2 className="text-lg font-bold">Create Course</h2>
        <div className="space-y-3">
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-sm font-medium mb-1 block">Name *</label>
              <Input value={form.name} onChange={(e) => set("name", e.target.value)} placeholder="e.g. Data Structures" />
            </div>
            <div>
              <label className="text-sm font-medium mb-1 block">Code *</label>
              <Input value={form.code} onChange={(e) => set("code", e.target.value)} placeholder="e.g. CS201" />
            </div>
          </div>
          <div>
            <label className="text-sm font-medium mb-1 block">Description</label>
            <textarea className="w-full border rounded-md px-3 py-2 text-sm min-h-[70px]" value={form.description} onChange={(e) => set("description", e.target.value)} placeholder="Course description..." />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-sm font-medium mb-1 block">Department</label>
              <select className="w-full border rounded-md px-3 py-2 text-sm bg-background" value={form.departmentId} onChange={(e) => set("departmentId", e.target.value)}>
                <option value="">None</option>
                {departments.map((d: any) => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
            </div>
            <div>
              <label className="text-sm font-medium mb-1 block">Credits</label>
              <Input type="number" value={form.credits} onChange={(e) => set("credits", e.target.value)} />
            </div>
          </div>
        </div>
        <div className="flex gap-3 justify-end">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button onClick={handleSave} disabled={saving}>{saving ? "Saving..." : "Create"}</Button>
        </div>
      </div>
    </div>
  );
}

export default function AdminCoursesPage() {
  const [showForm, setShowForm] = useState(false);
  const [search, setSearch] = useState("");
  const qc = useQueryClient();

  const { data: courses = [], isLoading } = useQuery<any[]>({ queryKey: ["courses"], queryFn: () => api.get("/courses") });
  const { data: departments = [] } = useQuery<any[]>({ queryKey: ["departments"], queryFn: () => api.get("/departments") });

  const filtered = courses.filter((c: any) =>
    c.name.toLowerCase().includes(search.toLowerCase()) || c.code.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">Courses</h1>
            <p className="text-muted-foreground mt-1">Manage all courses on the platform.</p>
          </div>
          <Button onClick={() => setShowForm(true)}><Plus className="h-4 w-4 mr-2" /> Create Course</Button>
        </div>

        <Input placeholder="Search by name or code..." className="max-w-xs" value={search} onChange={(e) => setSearch(e.target.value)} />

        {isLoading ? (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {[1, 2, 3].map((i) => <Card key={i} className="h-36 animate-pulse bg-muted" />)}
          </div>
        ) : filtered.length === 0 ? (
          <Card>
            <CardContent className="py-12 flex flex-col items-center gap-2 text-muted-foreground">
              <BookOpen className="h-8 w-8 opacity-40" />
              <p className="text-sm">No courses found.</p>
            </CardContent>
          </Card>
        ) : (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {filtered.map((c: any) => (
              <Card key={c.id}>
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <CardTitle className="text-base">{c.name}</CardTitle>
                      <p className="text-xs font-mono text-muted-foreground">{c.code}</p>
                    </div>
                    <Badge variant="outline">{c.credits} cr</Badge>
                  </div>
                </CardHeader>
                <CardContent className="space-y-2">
                  {c.description && <p className="text-xs text-muted-foreground">{c.description}</p>}
                  <p className="text-xs text-muted-foreground">{c.departmentName ?? "No department"}</p>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      {showForm && <CourseForm departments={departments} onClose={() => setShowForm(false)} onSave={() => qc.invalidateQueries({ queryKey: ["courses"] })} />}
    </DashboardLayout>
  );
}

import { useQuery, useQueryClient } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { Megaphone, Plus, Trash2 } from "lucide-react";
import { useState } from "react";

function AnnouncementForm({ courses, onClose, onSave }: { courses: any[]; onClose: () => void; onSave: () => void }) {
  const [form, setForm] = useState({ courseId: "", title: "", content: "" });
  const [saving, setSaving] = useState(false);
  const set = (k: string, v: string) => setForm((f) => ({ ...f, [k]: v }));

  const handleSave = async () => {
    if (!form.title || !form.content) { alert("Title and content required"); return; }
    setSaving(true);
    try {
      await api.post("/announcements", { ...form, courseId: form.courseId ? Number(form.courseId) : null });
      onSave(); onClose();
    } catch (e: any) { alert(e.message); }
    setSaving(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-card rounded-lg border p-6 w-full max-w-lg space-y-4">
        <h2 className="text-lg font-bold">Post Announcement</h2>
        <div className="space-y-3">
          <div>
            <label className="text-sm font-medium mb-1 block">Target (leave blank for global)</label>
            <select className="w-full border rounded-md px-3 py-2 text-sm bg-background" value={form.courseId} onChange={(e) => set("courseId", e.target.value)}>
              <option value="">Global — All users</option>
              {courses.map((c: any) => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="text-sm font-medium mb-1 block">Title *</label>
            <Input value={form.title} onChange={(e) => set("title", e.target.value)} placeholder="Announcement title..." />
          </div>
          <div>
            <label className="text-sm font-medium mb-1 block">Content *</label>
            <textarea
              className="w-full border rounded-md px-3 py-2 text-sm min-h-[120px]"
              value={form.content}
              onChange={(e) => set("content", e.target.value)}
              placeholder="Write your announcement..."
            />
          </div>
        </div>
        <div className="flex gap-3 justify-end">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button onClick={handleSave} disabled={saving}>{saving ? "Posting..." : "Post"}</Button>
        </div>
      </div>
    </div>
  );
}

export default function AdminAnnouncementsPage() {
  const [showForm, setShowForm] = useState(false);
  const qc = useQueryClient();

  const { data: announcements = [], isLoading } = useQuery<any[]>({
    queryKey: ["announcements"],
    queryFn: () => api.get("/announcements"),
  });
  const { data: courses = [] } = useQuery<any[]>({ queryKey: ["courses"], queryFn: () => api.get("/courses") });

  const deleteAnnouncement = async (id: number) => {
    if (!confirm("Delete this announcement?")) return;
    await api.del(`/announcements/${id}`);
    qc.invalidateQueries({ queryKey: ["announcements"] });
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">Announcements</h1>
            <p className="text-muted-foreground mt-1">Post announcements to students and staff.</p>
          </div>
          <Button onClick={() => setShowForm(true)}><Plus className="h-4 w-4 mr-2" /> Post Announcement</Button>
        </div>

        {isLoading ? (
          <div className="space-y-4">
            {[1, 2].map((i) => <Card key={i} className="h-32 animate-pulse bg-muted" />)}
          </div>
        ) : announcements.length === 0 ? (
          <Card>
            <CardContent className="py-12 flex flex-col items-center gap-2 text-muted-foreground">
              <Megaphone className="h-8 w-8 opacity-40" />
              <p className="text-sm">No announcements yet.</p>
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-4">
            {announcements.map((a: any) => (
              <Card key={a.id}>
                <CardHeader className="pb-2">
                  <div className="flex items-start justify-between gap-4">
                    <div>
                      <CardTitle className="text-base">{a.title}</CardTitle>
                      <p className="text-xs text-muted-foreground mt-0.5">
                        By {a.authorName} · {new Date(a.createdAt).toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" })}
                      </p>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <Badge variant="outline">{a.courseName ?? "Global"}</Badge>
                      <Button size="sm" variant="ghost" className="text-destructive h-8 w-8 p-0" onClick={() => deleteAnnouncement(a.id)}>
                        <Trash2 className="h-3.5 w-3.5" />
                      </Button>
                    </div>
                  </div>
                </CardHeader>
                <CardContent>
                  <p className="text-sm whitespace-pre-wrap">{a.content}</p>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      {showForm && <AnnouncementForm courses={courses} onClose={() => setShowForm(false)} onSave={() => qc.invalidateQueries({ queryKey: ["announcements"] })} />}
    </DashboardLayout>
  );
}

import { Switch, Route, Router as WouterRouter, useLocation } from "wouter";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { AuthProvider, useAuth } from "@/hooks/use-auth";

import NotFound from "@/pages/not-found";
import Login from "@/pages/login";
import DashboardRouter from "@/pages/dashboard";

import SuperAdminDashboard from "@/pages/super-admin";

import AdminDashboard from "@/pages/admin";
import AdminUsersPage from "@/pages/admin/users";
import AdminCoursesPage from "@/pages/admin/courses";
import AdminAnnouncementsPage from "@/pages/admin/announcements";

import LecturerDashboard from "@/pages/lecturer";
import LecturerExamsPage from "@/pages/lecturer/exams";
import LecturerLivePage from "@/pages/lecturer/live";
import LecturerMaterialsPage from "@/pages/lecturer/materials";
import LecturerAssignmentsPage from "@/pages/lecturer/assignments";
import LecturerProctoringPage from "@/pages/lecturer/proctoring";

import StudentDashboard from "@/pages/student";
import StudentExamsPage from "@/pages/student/exams";
import StudentLivePage from "@/pages/student/live";
import StudentMaterialsPage from "@/pages/student/materials";
import StudentAssignmentsPage from "@/pages/student/assignments";
import StudentAnnouncementsPage from "@/pages/student/announcements";

const queryClient = new QueryClient({
  defaultOptions: { queries: { retry: 1, staleTime: 30_000 } },
});

function ProtectedRoute({ component: Component, allowedRoles }: { component: React.ComponentType; allowedRoles?: string[] }) {
  const { isAuthenticated, isLoading, user } = useAuth();
  const [_, setLocation] = useLocation();

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="w-6 h-6 border-2 border-primary border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  if (!isAuthenticated) {
    setLocation("/login");
    return null;
  }

  if (allowedRoles && user && !allowedRoles.includes(user.role)) {
    setLocation("/unauthorized");
    return null;
  }

  return <Component />;
}

function Unauthorized() {
  const [_, setLocation] = useLocation();
  return (
    <div className="min-h-screen flex flex-col items-center justify-center text-center px-4">
      <h1 className="text-4xl font-bold mb-4">Unauthorized</h1>
      <p className="text-muted-foreground mb-8">You don't have permission to view this page.</p>
      <button onClick={() => setLocation("/dashboard")} className="px-4 py-2 bg-primary text-primary-foreground rounded-md font-medium">
        Return to Dashboard
      </button>
    </div>
  );
}

function Router() {
  return (
    <Switch>
      <Route path="/login" component={Login} />
      <Route path="/" component={DashboardRouter} />
      <Route path="/dashboard" component={DashboardRouter} />
      <Route path="/unauthorized" component={Unauthorized} />

      {/* Super Admin */}
      <Route path="/super-admin">{() => <ProtectedRoute component={SuperAdminDashboard} allowedRoles={["super_admin"]} />}</Route>

      {/* Admin */}
      <Route path="/admin">{() => <ProtectedRoute component={AdminDashboard} allowedRoles={["admin", "super_admin"]} />}</Route>
      <Route path="/admin/users">{() => <ProtectedRoute component={AdminUsersPage} allowedRoles={["admin", "super_admin"]} />}</Route>
      <Route path="/admin/courses">{() => <ProtectedRoute component={AdminCoursesPage} allowedRoles={["admin", "super_admin"]} />}</Route>
      <Route path="/admin/announcements">{() => <ProtectedRoute component={AdminAnnouncementsPage} allowedRoles={["admin", "super_admin"]} />}</Route>

      {/* Lecturer */}
      <Route path="/lecturer">{() => <ProtectedRoute component={LecturerDashboard} allowedRoles={["lecturer"]} />}</Route>
      <Route path="/lecturer/exams">{() => <ProtectedRoute component={LecturerExamsPage} allowedRoles={["lecturer"]} />}</Route>
      <Route path="/lecturer/live">{() => <ProtectedRoute component={LecturerLivePage} allowedRoles={["lecturer"]} />}</Route>
      <Route path="/lecturer/materials">{() => <ProtectedRoute component={LecturerMaterialsPage} allowedRoles={["lecturer"]} />}</Route>
      <Route path="/lecturer/assignments">{() => <ProtectedRoute component={LecturerAssignmentsPage} allowedRoles={["lecturer"]} />}</Route>
      <Route path="/lecturer/proctoring">{() => <ProtectedRoute component={LecturerProctoringPage} allowedRoles={["lecturer"]} />}</Route>

      {/* Student */}
      <Route path="/student">{() => <ProtectedRoute component={StudentDashboard} allowedRoles={["student"]} />}</Route>
      <Route path="/student/exams">{() => <ProtectedRoute component={StudentExamsPage} allowedRoles={["student"]} />}</Route>
      <Route path="/student/live">{() => <ProtectedRoute component={StudentLivePage} allowedRoles={["student"]} />}</Route>
      <Route path="/student/materials">{() => <ProtectedRoute component={StudentMaterialsPage} allowedRoles={["student"]} />}</Route>
      <Route path="/student/assignments">{() => <ProtectedRoute component={StudentAssignmentsPage} allowedRoles={["student"]} />}</Route>
      <Route path="/student/announcements">{() => <ProtectedRoute component={StudentAnnouncementsPage} allowedRoles={["student"]} />}</Route>

      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AuthProvider>
        <TooltipProvider>
          <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
            <Router />
          </WouterRouter>
          <Toaster />
        </TooltipProvider>
      </AuthProvider>
    </QueryClientProvider>
  );
}

export default App;

