    16→  
    17→  const { data: user, isLoading, refetch } = useGetMe({
    18→    query: {
    19→      enabled: !!token,
    20→      retry: false,
    21→    }
    22→  });
    23→
    24→  const login = (newToken: string) => {
    25→    localStorage.setItem("oems_token", newToken);
    26→    setToken(newToken);
    27→    refetch();
    28→  };
    29→
    30→  const logout = () => {
    31→    localStorage.removeItem("oems_token");
    32→    setToken(null);
    33→  };
    34→
    35→  return (
    36→    <AuthContext.Provider
    37→      value={{
    38→        user: user ?? null,
    39→        isLoading: isLoading && !!token,
    40→        login,
    41→        logout,
    42→        isAuthenticated: !!user,
    43→      }}
    44→    >
    45→      {children}
    46→    </AuthContext.Provider>
    47→  );
    48→}
