    40→ * NOTE: This function should never be used in web applications where session
    41→ * token cookies are automatically associated with API calls by the browser.
    42→ */
    43→export function setAuthTokenGetter(getter: AuthTokenGetter | null): void {
    44→  _authTokenGetter = getter;
    45→}
