    47→function isRequest(input: RequestInfo | URL): input is Request {
    48→  return typeof Request !== "undefined" && input instanceof Request;
    49→}
    50→
    51→function resolveMethod(input: RequestInfo | URL, explicitMethod?: string): string {
    52→  if (explicitMethod) return explicitMethod.toUpperCase();
    53→  if (isRequest(input)) return input.method.toUpperCase();
    54→  return "GET";
    55→}
    56→
    57→// Use loose check for URL — some runtimes (e.g. React Native) polyfill URL
    58→// differently, so `instanceof URL` can fail.
    59→function isUrl(input: RequestInfo | URL): input is URL {
    60→  return typeof URL !== "undefined" && input instanceof URL;
    61→}
    62→
    63→function applyBaseUrl(input: RequestInfo | URL): RequestInfo | URL {
    64→  if (!_baseUrl) return input;
    65→  const url = resolveUrl(input);
    66→  // Only prepend to relative paths (starting with /)
    67→  if (!url.startsWith("/")) return input;
    68→
    69→  const absolute = `${_baseUrl}${url}`;
    70→  if (typeof input === "string") return absolute;
    71→  if (isUrl(input)) return new URL(absolute);
    72→  return new Request(absolute, input as Request);
    73→}
    74→
    75→function resolveUrl(input: RequestInfo | URL): string {
    76→  if (typeof input === "string") return input;
    77→  if (isUrl(input)) return input.toString();
    78→  return input.url;
    79→}
    80→
    81→function mergeHeaders(...sources: Array<HeadersInit | undefined>): Headers {
    82→  const headers = new Headers();
    83→
    84→  for (const source of sources) {
    85→    if (!source) continue;
    86→    new Headers(source).forEach((value, key) => {
    87→      headers.set(key, value);
    88→    });
    89→  }
    90→
    91→  return headers;
    92→}
    93→
    94→function getMediaType(headers: Headers): string | null {
    95→  const value = headers.get("content-type");
    96→  return value ? value.split(";", 1)[0].trim().toLowerCase() : null;
    97→}
    98→
    99→function isJsonMediaType(mediaType: string | null): boolean {
   100→  return mediaType === "application/json" || Boolean(mediaType?.endsWith("+json"));
   101→}
   102→
   103→function isTextMediaType(mediaType: string | null): boolean {
   104→  return Boolean(
   105→    mediaType &&
   106→      (mediaType.startsWith("text/") ||
   107→        mediaType === "application/xml" ||
   108→        mediaType === "text/xml" ||
   109→        mediaType.endsWith("+xml") ||
   110→        mediaType === "application/x-www-form-urlencoded"),
   111→  );
   112→}
