   114→// Use strict equality: in browsers, `response.body` is `null` when the
   115→// response genuinely has no content.  In React Native, `response.body` is
   116→// always `undefined` because the ReadableStream API is not implemented —
   117→// even when the response carries a full payload readable via `.text()` or
   118→// `.json()`.  Loose equality (`== null`) matches both `null` and `undefined`,
   119→// which causes every React Native response to be treated as empty.
   120→function hasNoBody(response: Response, method: string): boolean {
   121→  if (method === "HEAD") return true;
   122→  if (NO_BODY_STATUS.has(response.status)) return true;
   123→  if (response.headers.get("content-length") === "0") return true;
   124→  if (response.body === null) return true;
   125→  return false;
   126→}
   127→
   128→function stripBom(text: string): string {
   129→  return text.charCodeAt(0) === 0xfeff ? text.slice(1) : text;
   130→}
   131→
   132→function looksLikeJson(text: string): boolean {
   133→  const trimmed = text.trimStart();
   134→  return trimmed.startsWith("{") || trimmed.startsWith("[");
   135→}
   136→
   137→function getStringField(value: unknown, key: string): string | undefined {
   138→  if (!value || typeof value !== "object") return undefined;
   139→
   140→  const candidate = (value as Record<string, unknown>)[key];
   141→  if (typeof candidate !== "string") return undefined;
   142→
   143→  const trimmed = candidate.trim();
   144→  return trimmed === "" ? undefined : trimmed;
   145→}
   146→
   147→function truncate(text: string, maxLength = 300): string {
   148→  return text.length > maxLength ? `${text.slice(0, maxLength - 1)}…` : text;
   149→}
   150→
   151→function buildErrorMessage(response: Response, data: unknown): string {
   152→  const prefix = `HTTP ${response.status} ${response.statusText}`;
   153→
   154→  if (typeof data === "string") {
   155→    const text = data.trim();
   156→    return text ? `${prefix}: ${truncate(text)}` : prefix;
   157→  }
   158→
   159→  const title = getStringField(data, "title");
   160→  const detail = getStringField(data, "detail");
   161→  const message =
   162→    getStringField(data, "message") ??
   163→    getStringField(data, "error_description") ??
   164→    getStringField(data, "error");
   165→
   166→  if (title && detail) return `${prefix}: ${title} — ${detail}`;
   167→  if (detail) return `${prefix}: ${detail}`;
   168→  if (message) return `${prefix}: ${message}`;
   169→  if (title) return `${prefix}: ${title}`;
   170→
   171→  return prefix;
   172→}
