   174→export class ApiError<T = unknown> extends Error {
   175→  readonly name = "ApiError";
   176→  readonly status: number;
   177→  readonly statusText: string;
   178→  readonly data: T | null;
   179→  readonly headers: Headers;
   180→  readonly response: Response;
   181→  readonly method: string;
   182→  readonly url: string;
   183→
   184→  constructor(
   185→    response: Response,
   186→    data: T | null,
   187→    requestInfo: { method: string; url: string },
   188→  ) {
   189→    super(buildErrorMessage(response, data));
   190→    Object.setPrototypeOf(this, new.target.prototype);
   191→
   192→    this.status = response.status;
   193→    this.statusText = response.statusText;
   194→    this.data = data;
   195→    this.headers = response.headers;
   196→    this.response = response;
   197→    this.method = requestInfo.method;
   198→    this.url = response.url || requestInfo.url;
   199→  }
   200→}
