   202→export class ResponseParseError extends Error {
   203→  readonly name = "ResponseParseError";
   204→  readonly status: number;
   205→  readonly statusText: string;
   206→  readonly headers: Headers;
   207→  readonly response: Response;
   208→  readonly method: string;
   209→  readonly url: string;
   210→  readonly rawBody: string;
   211→  readonly cause: unknown;
   212→
   213→  constructor(
   214→    response: Response,
   215→    rawBody: string,
   216→    cause: unknown,
   217→    requestInfo: { method: string; url: string },
   218→  ) {
   219→    super(
   220→      `Failed to parse response from ${requestInfo.method} ${response.url || requestInfo.url} ` +
   221→        `(${response.status} ${response.statusText}) as JSON`,
   222→    );
   223→    Object.setPrototypeOf(this, new.target.prototype);
   224→
   225→    this.status = response.status;
   226→    this.statusText = response.statusText;
   227→    this.headers = response.headers;
   228→    this.response = response;
   229→    this.method = requestInfo.method;
   230→    this.url = response.url || requestInfo.url;
   231→    this.rawBody = rawBody;
   232→    this.cause = cause;
   233→  }
   234→}
