    11→
    12→export function signToken(payload: AuthPayload): string {
    13→  const header = Buffer.from(JSON.stringify({ alg: "HS256", typ: "JWT" })).toString("base64url");
    14→  const body = Buffer.from(JSON.stringify({ ...payload, iat: Date.now() })).toString("base64url");
    15→  const sig = createHmac("sha256", JWT_SECRET).update(`${header}.${body}`).digest("base64url");
    16→  return `${header}.${body}.${sig}`;
    17→}
    18→
    19→export function verifyToken(token: string): AuthPayload | null {
    20→  try {
    21→    const [header, body, sig] = token.split(".");
    22→    const expected = createHmac("sha256", JWT_SECRET).update(`${header}.${body}`).digest("base64url");
    23→    if (sig !== expected) return null;
    24→    return JSON.parse(Buffer.from(body, "base64url").toString());
    25→  } catch {
    26→    return null;
    27→  }
    28→}
