    30→export function requireAuth(req: Request, res: Response, next: NextFunction): void {
    31→  const authHeader = req.headers.authorization;
    32→  if (!authHeader?.startsWith("Bearer ")) {
    33→    res.status(401).json({ error: "Unauthorized" });
    34→    return;
    35→  }
    36→  const token = authHeader.slice(7);
    37→  const payload = verifyToken(token);
    38→  if (!payload) {
    39→    res.status(401).json({ error: "Invalid token" });
    40→    return;
    41→  }
    42→  (req as Request & { user: AuthPayload }).user = payload;
    43→  next();
    44→}
    45→
    46→export function requireRole(...roles: string[]) {
    47→  return (req: Request, res: Response, next: NextFunction): void => {
    48→    const user = (req as Request & { user?: AuthPayload }).user;
    49→    if (!user || !roles.includes(user.role)) {
    50→      res.status(403).json({ error: "Forbidden" });
    51→      return;
    52→    }
    53→    next();
    54→  };
    55→}
